Activity.JQScript:
# Prepare bulk EXPORTMI.Select for MPLINE table using FAPIBA data
# Input: EXPORTMI_FAPIBA response
# Output: Bulk EXPORTMI.Select requests for MPLINE where UCA1 equals each REPL from FAPIBA

{
  program: "EXPORTMI",
  transactions: [
    .results[] | .records[] |
    {
      transaction: "Select",
      record: {
        SEPC: ";",
        QERY: "IBPUNO, IBPNLI, IBPNLS, IBUDN1, IBRVQA from MPLINE where IBUCA1 = '\(.REPL)' and IBPUSL < 85"
      }
    }
  ]
}

# Prepare bulk EXPORTMI.Select for MPOEXP table using PDNLIN data
# Input: { ceid: "value", POLines: EXPORTMI_PDNLIN, CUSEXTMI: CUSEXTMI_GetFieldValue }
# Fields from PDNLIN (split by ;): ILRIDN (PUNO), ILRIDL (PNLI), ILRIDX (PNLS), ILDLQA, ILWHLO, ILSUNO, ILDNDT, ILSUDO, ILITNO
# Only create requests if CUSEXTMI A030 field equals empty string

# Extract A030 value from CUSEXTMI response
(.CUSEXTMI.results[0].records[0].A030 // "") as $a030 |
.ceid as $ceid |

# Split each REPL value by semicolon and create MPOEXP queries only if A030 is empty
{
  program: "EXPORTMI",
  transactions: (
    if $a030 == "B" then
      [
        .POLines.results[] | .records[] | 
        (.REPL | split(";")) as $fields |
        {
          transaction: "Select",
          record: {
            SEPC: ";",
            QERY: "IVPUNO, IVPNLI, IVPNLS, IVCEVA from MPOEXP where IVPUNO = '\($fields[0])' and IVPNLI = '\($fields[1])' and IVPNLS = '\($fields[2])' and IVCEID = '\($ceid)'"
          }
        }
      ]
    else
      []
    end
  )
}
